	return s.claim(id, assignee, session, worktree)
}

func (s *claimSuccessRateWarningStore) claim(id, assignee, session, worktree string) error {
	attempt := s.attempts.Add(1)
	switch attempt {
	case 1, 2, 3, 5:
		if attempt == 5 && s.cancel != nil {
